// Items with weights {1, 3, 4, 5} and values {1, 4, 5, 7}
// A knapsack (bag) can carry AT MOST a total weight of 7
// Each item can be taken ONCE (0/1 — take it or don't, no fractions, no duplicates)
// Maximize the total VALUE that fits in the bag

// At item i, there are exactly two choices, just like House Robber's skip-or-take:
// SKIP item i -> dp[i-1][w] (capacity untouched, value unchanged)
// TAKE item i (only if it FITS: weight[i] <= w) -> value[i] + dp[i-1][w - weight[i]]

// dp[i][w] = max(dp[i-1][w], value[i] + dp[i-1][w - weight[i]])   if weight[i] <= w
// dp[i][w] = dp[i-1][w]                                           otherwise (doesn't fit)

#include <iostream>
#include <vector>

using namespace std;

int knapsack(vector<int> &weights, vector<int> &values, int capacity)
{
    int n = weights.size();
    vector<vector<int>> dp(n + 1, vector<int>(capacity + 1, 0));

    for (int i = 1; i <= n; i++)
    {
        for (int w = 0; w <= capacity; w++)
        {
            dp[i][w] = dp[i - 1][w]; // skip item i-1 (0-indexed)

            if (weights[i - 1] <= w) // item fits, consider taking it
            {
                dp[i][w] = max(dp[i][w], values[i - 1] + dp[i - 1][w - weights[i - 1]]);
            }
        }
    }

    return dp[n][capacity];
}

int main()
{
    vector<int> weights = {1, 3, 4, 5};
    vector<int> values = {1, 4, 5, 7};
    int capacity = 7;

    cout << knapsack(weights, values, capacity) << endl;

    return 0;
}

