#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

int findMaxForm(vector<string>& strs, int m, int n)
{
    int k = strs.size();
    vector<vector<vector<int>>> dp(k + 1, vector<vector<int>>(m + 1, vector<int>(n + 1, 0)));

    for (int s = 1; s <= k; s++)
    {
        int zeros = 0, ones = 0;
        for (char c : strs[s - 1]) (c == '0') ? zeros++ : ones++;

        for (int i = 0; i <= m; i++)
            for (int j = 0; j <= n; j++)
            {
                dp[s][i][j] = dp[s - 1][i][j];
                if (zeros <= i && ones <= j)
                    dp[s][i][j] = max(dp[s][i][j], dp[s - 1][i - zeros][j - ones] + 1);
            }
    }

    return dp[k][m][n];
}

int main()
{
    vector<string> strs = {"10", "0001", "111001", "1", "0"};
    cout << findMaxForm(strs, 5, 3);

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

int findMaxForm(vector<string>& strs, int m, int n)
{
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

    for (auto &str : strs)
    {
        int zeros = 0, ones = 0;
        for (char c : str) (c == '0') ? zeros++ : ones++;

        for (int i = m; i >= zeros; i--)
            for (int j = n; j >= ones; j--)
                dp[i][j] = max(dp[i][j], dp[i - zeros][j - ones] + 1);
    }

    return dp[m][n];
}

int main()
{
    vector<string> strs = {"10", "0001", "111001", "1", "0"};
    cout << findMaxForm(strs, 5, 3);

    return 0;
}

